package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.Instant;
import java.time.LocalDate;
import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that assigns trading events to windows aligned with market session
 * boundaries. Unlike fixed-interval windows, each window spans exactly one trading session (e.g.,
 * NYSE 09:30–16:00 ET, LSE 08:00–16:30 GMT), so aggregations naturally align with market open and
 * close times.
 *
 * <p>Example usage for NYSE:
 *
 * <pre>{@code
 * DataStream<TradeEvent> trades = ...;
 * trades.keyBy(TradeEvent::getSymbol)
 *       .window(PricingSessionWindow.forMarket(
 *           "NYSE",
 *           ZoneId.of("America/New_York"),
 *           LocalTime.of(9, 30),
 *           LocalTime.of(16, 0)))
 *       .aggregate(...);
 * }</pre>
 *
 * <p>Overnight sessions (where {@code sessionClose} is before {@code sessionOpen} in wall-clock
 * time, e.g., CME futures 18:00–17:00 next day) are supported: the window spans midnight and ends
 * the following calendar day.
 *
 * <p>Elements whose timestamps fall outside an active session (pre-market or post-market) are
 * assigned to the nearest upcoming session window so that no events are silently dropped.
 *
 * <p>Window merging is delegated to {@link TimeWindow#mergeWindows} to handle any overlapping
 * windows that may arise from late or out-of-order data.
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {

    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    private PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    /**
     * Creates a {@code PricingSessionWindow} for the given market.
     *
     * @param marketId A human-readable identifier for the market (e.g., "NYSE", "LSE").
     * @param timezone The timezone in which {@code sessionOpen} and {@code sessionClose} are
     *     expressed.
     * @param sessionOpen The local time at which the trading session opens each day.
     * @param sessionClose The local time at which the trading session closes each day. If {@code
     *     sessionClose} is before {@code sessionOpen} the session is treated as an overnight session
     *     that spans midnight.
     * @return A configured {@code PricingSessionWindow} assigner.
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        return new PricingSessionWindow(marketId, timezone, sessionOpen, sessionClose);
    }

    /**
     * Assigns the element to the {@link TimeWindow} that represents the trading session containing
     * the element's event timestamp.
     *
     * <p>For a normal session (open &lt; close in wall-clock time):
     *
     * <ul>
     *   <li>If the timestamp falls within [open, close) on day D, the window is [open_D, close_D).
     *   <li>If the timestamp falls before open on day D (pre-market), the window is [open_D,
     *       close_D) — the element is assigned to the upcoming session.
     *   <li>If the timestamp falls at or after close on day D (post-market), the window is
     *       [open_{D+1}, close_{D+1}).
     * </ul>
     *
     * <p>For an overnight session (close &lt; open in wall-clock time):
     *
     * <ul>
     *   <li>If the timestamp falls before close on day D, the element is in the tail of the session
     *       that opened on day D-1: window is [open_{D-1}, close_D).
     *   <li>Otherwise the element is in the session that opens on day D: window is [open_D,
     *       close_{D+1}).
     * </ul>
     */
    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        ZonedDateTime zdt = Instant.ofEpochMilli(timestamp).atZone(timezone);
        LocalDate date = zdt.toLocalDate();
        LocalTime time = zdt.toLocalTime();

        long windowStart;
        long windowEnd;

        if (!sessionClose.isBefore(sessionOpen)) {
            // Normal intra-day session (open <= close)
            windowStart = toEpochMilli(date, sessionOpen);
            windowEnd = toEpochMilli(date, sessionClose);

            if (timestamp >= windowEnd) {
                // Post-market: assign to next day's session
                LocalDate nextDate = date.plusDays(1);
                windowStart = toEpochMilli(nextDate, sessionOpen);
                windowEnd = toEpochMilli(nextDate, sessionClose);
            }
            // Pre-market (timestamp < windowStart) stays in the current day's session window
        } else {
            // Overnight session (close < open, e.g., 18:00 – 17:00 next day)
            if (time.isBefore(sessionClose)) {
                // Tail of the overnight session: started previous day
                LocalDate prevDate = date.minusDays(1);
                windowStart = toEpochMilli(prevDate, sessionOpen);
                windowEnd = toEpochMilli(date, sessionClose);
            } else {
                // Head of the overnight session: ends next day
                windowStart = toEpochMilli(date, sessionOpen);
                windowEnd = toEpochMilli(date.plusDays(1), sessionClose);
            }
        }

        return Collections.singletonList(new TimeWindow(windowStart, windowEnd));
    }

    /** Converts a {@link LocalDate} and {@link LocalTime} in this assigner's timezone to epoch ms. */
    private long toEpochMilli(LocalDate date, LocalTime time) {
        return date.atTime(time).atZone(timezone).toInstant().toEpochMilli();
    }

    /** Returns the market identifier supplied at construction time. */
    public String getMarketId() {
        return marketId;
    }

    /** Returns the timezone in which session boundaries are expressed. */
    public ZoneId getTimezone() {
        return timezone;
    }

    /** Returns the local time at which the trading session opens. */
    public LocalTime getSessionOpen() {
        return sessionOpen;
    }

    /** Returns the local time at which the trading session closes. */
    public LocalTime getSessionClose() {
        return sessionClose;
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return EventTimeTrigger.create();
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    /** Merges overlapping {@link TimeWindow}s by delegating to {@link TimeWindow#mergeWindows}. */
    @Override
    public void mergeWindows(
            Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
        TimeWindow.mergeWindows(windows, c);
    }

    @Override
    public String toString() {
        return "PricingSessionWindow{"
                + "marketId='"
                + marketId
                + '\''
                + ", timezone="
                + timezone
                + ", open="
                + sessionOpen
                + ", close="
                + sessionClose
                + '}';
    }
}

