package org.apache.flink.streaming.api.windowing.triggers;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.functions.ReduceFunction;
import org.apache.flink.api.common.state.ReducingState;
import org.apache.flink.api.common.state.ReducingStateDescriptor;
import org.apache.flink.api.common.typeutils.base.LongSerializer;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

/**
 * A {@link Trigger} for use with {@link
 * org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow} that fires when the
 * event-time watermark passes the end of the trading session (market close).
 *
 * <p>In addition to the standard end-of-session fire, the trigger supports <em>early firing</em>
 * for exceptional market events such as circuit-breaker halts. An early-fire timestamp can be
 * registered via {@link #withEarlyFiringAt(long)} and will cause the window to emit results before
 * the session closes. The earliest registered early-fire time is retained across merges.
 *
 * <p>The trigger supports window merging ({@link #canMerge()} returns {@code true}): on merge the
 * end-of-session timer is re-registered for the new (merged) window, and the earliest early-fire
 * timestamp is propagated.
 *
 * <p>Usage:
 *
 * <pre>{@code
 * PricingSessionTrigger trigger = PricingSessionTrigger.create();
 * // Optionally schedule an early fire (e.g., circuit-breaker halt at a known timestamp):
 * // trigger.withEarlyFiringAt(haltTimestamp);
 * }</pre>
 */
@PublicEvolving
public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {

    private static final long serialVersionUID = 1L;

    /**
     * Persisted state holding the earliest scheduled early-fire timestamp. Using a {@link
     * ReducingState} with a {@code Min} reducer means that across merges the smallest (earliest)
     * timestamp is automatically retained.
     */
    private final ReducingStateDescriptor<Long> earlyFireStateDesc =
            new ReducingStateDescriptor<>("early-fire-time", new Min(), LongSerializer.INSTANCE);

    private PricingSessionTrigger() {}

    /**
     * Creates a new {@code PricingSessionTrigger} that fires at market close (window end).
     *
     * @return A new {@code PricingSessionTrigger}.
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }

    /**
     * Schedules an early fire at the given event-time timestamp. This is intended for exceptional
     * market events such as circuit-breaker trading halts. The trigger will fire (and emit partial
     * results) when the watermark reaches {@code earlyFireTimestamp}, in addition to the normal
     * end-of-session fire.
     *
     * <p>If called multiple times the earliest timestamp wins.
     *
     * @param earlyFireTimestamp The event-time timestamp at which to fire early (epoch ms).
     * @return This trigger (for chaining).
     */
    public PricingSessionTrigger withEarlyFiringAt(long earlyFireTimestamp) {
        // The actual timer registration must happen inside onElement/onMerge where we have a
        // TriggerContext. This method stores the requested timestamp so callers can pass it in;
        // the real scheduling is done in scheduleEarlyFire().
        this.requestedEarlyFireTimestamp = earlyFireTimestamp;
        return this;
    }

    /**
     * Requested early-fire timestamp set via {@link #withEarlyFiringAt(long)}. {@code
     * Long.MAX_VALUE} means no early fire has been requested.
     */
    private long requestedEarlyFireTimestamp = Long.MAX_VALUE;

    // -------------------------------------------------------------------------
    // Trigger callbacks
    // -------------------------------------------------------------------------

    @Override
    public TriggerResult onElement(
            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
            throws Exception {
        if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
            // Watermark already past window end — fire immediately.
            return TriggerResult.FIRE;
        }

        // Register the end-of-session (market close) timer.
        ctx.registerEventTimeTimer(window.maxTimestamp());

        // Register any requested early-fire timer.
        if (requestedEarlyFireTimestamp < Long.MAX_VALUE) {
            scheduleEarlyFire(requestedEarlyFireTimestamp, window, ctx);
        }

        return TriggerResult.CONTINUE;
    }

    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        if (time == window.maxTimestamp()) {
            // End-of-session fire (market close).
            return TriggerResult.FIRE;
        }

        // Check whether this is a scheduled early-fire.
        ReducingState<Long> earlyFireState = ctx.getPartitionedState(earlyFireStateDesc);
        Long earlyFireTime = earlyFireState.get();
        if (earlyFireTime != null && earlyFireTime == time) {
            earlyFireState.clear();
            // Fire early but do NOT purge — the session window continues until market close.
            return TriggerResult.FIRE;
        }

        return TriggerResult.CONTINUE;
    }

    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        return TriggerResult.CONTINUE;
    }

    // -------------------------------------------------------------------------
    // Merge support
    // -------------------------------------------------------------------------

    @Override
    public boolean canMerge() {
        return true;
    }

    /**
     * On merge, re-registers the end-of-session timer for the new (merged) window and propagates
     * the earliest early-fire timestamp from the merged windows.
     */
    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) throws Exception {
        // Merge early-fire state: the Min reducer keeps the earliest timestamp.
        ctx.mergePartitionedState(earlyFireStateDesc);

        long windowMaxTimestamp = window.maxTimestamp();
        if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(windowMaxTimestamp);
        }

        // Re-register the early-fire timer if one was merged in.
        Long earlyFireTime = ctx.getPartitionedState(earlyFireStateDesc).get();
        if (earlyFireTime != null && earlyFireTime > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(earlyFireTime);
        }
    }

    // -------------------------------------------------------------------------
    // Cleanup
    // -------------------------------------------------------------------------

    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        // Remove the end-of-session timer.
        ctx.deleteEventTimeTimer(window.maxTimestamp());

        // Remove any pending early-fire timer.
        ReducingState<Long> earlyFireState = ctx.getPartitionedState(earlyFireStateDesc);
        Long earlyFireTime = earlyFireState.get();
        if (earlyFireTime != null) {
            ctx.deleteEventTimeTimer(earlyFireTime);
            earlyFireState.clear();
        }
    }

    // -------------------------------------------------------------------------
    // Helpers
    // -------------------------------------------------------------------------

    private void scheduleEarlyFire(long earlyFireTimestamp, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // Only schedule if the early-fire time is before the window end and in the future.
        if (earlyFireTimestamp < window.maxTimestamp()
                && earlyFireTimestamp > ctx.getCurrentWatermark()) {
            ReducingState<Long> earlyFireState = ctx.getPartitionedState(earlyFireStateDesc);
            earlyFireState.add(earlyFireTimestamp);
            ctx.registerEventTimeTimer(earlyFireTimestamp);
        }
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }

    // -------------------------------------------------------------------------
    // State reducer
    // -------------------------------------------------------------------------

    private static class Min implements ReduceFunction<Long> {
        private static final long serialVersionUID = 1L;

        @Override
        public Long reduce(Long value1, Long value2) {
            return Math.min(value1, value2);
        }
    }
}
